const Q_CHEMISTRY_2019_MODEL_II=[{"id": "objective>Chemistry>2019-Model-II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following sugars is a product  of the condensation of monosaccharides?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Galactose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Maltose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Glucose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fructose</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Maltose is produced by the enzymatic hydrolysis of starch (a homopolysaccharide) catalyzed by the enzyme amylase.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : CHEMICAL AND PHYSICAL CHANGES"}, {"id": "objective>Chemistry>2019-Model-II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the reaction between sodium hydroxide and tetraoxosulphate (VI) solutions, what volume of 0.5 molar sodium hydroxide would exactly neutralize 10cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of 1.25 molar tetraoxosulphate (vi) acid?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">10cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">20cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">25cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equation of reaction <br/> 2NaOH + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> → Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> Concentration of a base, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> = 0.5M <br/> Volume of acid, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span> = 10cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Concentration of an acid, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span> = 1.25M <br/> Volume of base, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> = ? <br/> Recall:  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span><hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span><hr size=\"1\" />n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span></td><td style=\"text-align:center;\">------------</td><td style=\"text-align:center;\">(1)</td></tr></table></div> <br/>  <br/> N.B: From the equation, <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span><hr size=\"1\" />n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div> <br/>  <br/> From (1) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1.25 × 10<hr size=\"1\" />0.5 × V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">12.5<hr size=\"1\" />0.5V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td></tr></table></div> <br/> 25 = 0.5V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> = 50.0 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/>  <br/> </div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>2019-Model-II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many grammes of NaOH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> would be needed to produce 100.0 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a 0.20 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> NaOH, (aq)? [NaOH = 40.0]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.02 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.80 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20.0 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">800.0</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Amount (in moles) = Molarity × Volume <br/> Amount (in moles) = 0.20 mol/dm³ × 100.0 cm³ / 1000 cm³/dm³ = 0.020 moles <br/> Now, we can calculate the mass using the formula: <br/> Mass = Amount × Molar Mass <br/> Mass = 0.020 moles × 40.0 g/mol = 0.80 g <br/> So, the correct answer is:0.80 g</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2019-Model-II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the reaction: <br/> M + N → P; ΔH = +Q KJ <br/>  <br/> Which of the following would increase the concentration of the product?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increasing the temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the concentration of P</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adding a suitable catalyst</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Decreasing the temperature</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in temperature usually favours the side that is endothermic. And since the reaction above is endothermic, an increase in temperature will favor, the forward reaction, hence more of P will be produced.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2019-Model-II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A compound contains 40.0% carbon, 6.7% hydrogen and 53.3% oxygen. If the molar mass of the compound is 180. Find the molecular formula. <br/> [H = 1, C = 12, O = 16]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">C</td><td style=\"border:1px solid black;text-align:center;\">H</td><td style=\"border:1px solid black;text-align:center;\">O</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">% Composition</td><td style=\"border:1px solid black;text-align:center;\">40.0%</td><td style=\"border:1px solid black;text-align:center;\">6.7%</td><td style=\"border:1px solid black;text-align:center;\">53.3%</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Mass (g)</td><td style=\"border:1px solid black;text-align:center;\">40</td><td style=\"border:1px solid black;text-align:center;\">6.7</td><td style=\"border:1px solid black;text-align:center;\">53.3</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Number of mole</td><td style=\"border:1px solid black;text-align:center;\"> <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">40</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">12</span> = 3.33</td><td style=\"border:1px solid black;text-align:center;\"> <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">6.7</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">1</span> = 6.7</td><td style=\"border:1px solid black;text-align:center;\"> <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">53.3</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">16</span> = 3.33</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Divide by the <br/> smallest value</td><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">2</td><td style=\"border:1px solid black;text-align:center;\">1</td></tr></table></div> <br/>  <br/> Empirical formula = CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> Empirical mass = 12 + 2 + 16 = 30g/mol <br/> (Empirical mass)n = Molecular mass <br/> ∴ (30)n = 180 <br/> n = 6 <br/> (Empirical formula)n = Molecular formula  <br/> (CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span> = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>.</div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2019-Model-II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The IUPAC nomenclature of the compound  <br/> H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>C - CH(CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>) - CH(CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>) - CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3 - ethyl pentane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3, 4 dimethylhexane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2, 3 - dimethylpentane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 - ethyl pentane </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2019-Model-II/1.png\" style=\"position:relative;max-width:100%;\"/> <br/> 2, 3 - dimethylpentane  <br/>  <br/> - The longest continuous carbon chain is 5 and saturated  ⇒ pentane <br/> - Attachments (methyl) on the 2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">nd</span> and 3<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">rd</span> carbon from L - R.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2019-Model-II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following compounds determines the octane rating of petrol?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1, 2, 3 - trimethyl pentane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2, 3, 5 - trimethyl octane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2, 3, 5 - trimethyl pentane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2, 2, 4 - trimethyl pentane</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The octane rating of petrol is determined by the compound 2, 2, 4 - trimethyl pentane. The octane rating is a standard measure of the performance of an engine or aviation gasoline. The higher the octane number, the more compression the fuel can withstand before detonating. In broad terms, fuels with a higher octane rating are used in high-performance gasoline engines that require higher compression ratios. Therefore, the correct answer is '2, 2, 4 - trimethyl pentane'.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2019-Model-II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What mass of magnesium would be obtained by passing a current of 2 amperes for 2 hours 30 mins, through molten magnesium chloride? <br/> [1 faraday = 96,500C, Mg = 24]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.12g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.24</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.80g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.48g</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Current (I) = 2A <br/> time (t) = 2 hours 30 minites=(120 + 30)=150 * 60= 9000s. <br/> Recall: Q = It <br/> Q = 2 × 9000 = 18,000C  <br/> 1F = 96500 <br/> x = 18,000 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x<hr size=\"1\" />1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">18,000<hr size=\"1\" />96,500</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">144<hr size=\"1\" />965</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.187F</td></tr></table></div> <br/>  <br/> Mg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Mg <br/> 2F → 24g <br/> 0.187F → x <br/>  <br/> 2x = 24 × 0.187 <br/> 2x = 4.488 <br/> x = 2.244g</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2019-Model-II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which important nitrogen-containing compound is produced in Haber's process?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">HNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Harber's process is an industrial process for the production of ammonia using finely divided iron as catalyst.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : NITROGEN"}, {"id": "objective>Chemistry>2019-Model-II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Elements in the periodic table are arranged in the order of their </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">relative atomic mass </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mass number </div>", "<div style=\"font-family:Cambria;font-size:17px;\">metallic character </div>", "<div style=\"font-family:Cambria;font-size:17px;\">atomic numbers </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to the modern periodic law, elements are arranged in order of their increasing atomic number.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2019-Model-II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What volume of 0.100M sodium trioxonitrate (V) solution contains 5g of solute. <br/> [Na = 23, N = 14, O = 16]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.588 litres </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.7 litres </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.420 litres </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.35 litres </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Molar concentration = 0.1M <br/> mass (m) = 5.0g <br/> Molar mas of NaNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = 23 + 14 + 48 = 85 g/mol <br/> Volume = ? <br/> Molar concentration × molar mass = mass concentration -------------- (1) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Mass</td><td style=\"text-align:center;\">concentration</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">mass of solute<hr size=\"1\" />volume</td><td style=\"text-align:center;\">..(2)</td></tr></table></div> <br/>  <br/> From (1) <br/> 0.1 × 85 = 8.5 g/dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = Mass concentration <br/>  <br/> From (2) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">8.5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5<hr size=\"1\" />x</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">5<hr size=\"1\" />8.5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.588</td><td style=\"text-align:center;\">dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></td><td style=\"text-align:center;\">(Litres)</td></tr></table></div></div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2019-Model-II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The two ions responsible for hardness in water are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> and / or Mg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ca<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> and / or Na<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ca<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> and / or Mg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ca<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> and / or Li<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water hardness is a measure of the amount of dissolved calcium (Ca<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>) and magnesium (Mg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>) in a water sample.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>2019-Model-II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following could not be alkane?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">18</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">14</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Alkanes conform to general molecular formula C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\"></span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n + 2</span>. This implies the number of hydrogen atoms will be 2 greater than twice the number of carbon atoms. <br/> A, B and C conform to this, except (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n</span>)</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2019-Model-II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The electronic configuration of element Z is 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> 2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> 2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> 3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> 3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span>. What is the formula of the compound formed between Z and tetraoxosulphate (VI) ion.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ZSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Z<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Z<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>(SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Z<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Z = 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> 2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> 2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> 3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> 3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span> <br/> Z has atomic number = 13 <br/> Z is aluminium <br/> Aluminium Sulphate = Al<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> <br/> Al<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> → Al<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = (Z<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2019-Model-II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> - CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> ≡ C - H the hybridization in the compound is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> and sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> and sp</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sp</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">- sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> hydridization is found in carbon atoms with only single bonds around them. <br/> - sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> hybridization is found in carbon atoms with any double bond around them. <br/> - sp hybridization is found in carbon atoms with any triple bond around them. <br/> <img src=\"2019-Model-II/2.png\" style=\"position:relative;max-width:100%;\"/> <br/> a = sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>, b = sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>, c = sp, d = sp <br/> </div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2019-Model-II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The following are isoelectronic ions except </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Si<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> has 10 electrons  <br/> O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span> has 10 electrons  <br/> Mg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> has 10 electrons  <br/> Si<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> has 12 electrons  <br/>  <br/> ⇒ Si<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> is not isoelectronic with the rest.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2019-Model-II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Consider the reaction: <br/> A + 2B<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> ⇌ 2C + D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> (ΔH = +ve) <br/> What will be the effect of decrease in temperature on the reaction?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rate of forward reaction will increase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rate of backward reaction will increase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rates of forward and backward reactions are not affected </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium constant will shift</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: The equation below  <br/> A<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 2B<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → 2C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + D<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> <br/> When dealing with pressure in equilibrium, it's the gaseous components that are usually considered. <br/> Looking at above equation, the reactant equation has 2 moles of gaseous element and the product equation has 1 mole of gaseous element. <br/> Now in equilibrium, when there's a decrease in the system, the reaction with higher moles of gaseous element or compound is favoured, and when there's an increase in pressure in the system, the reaction with lesser amount of moles of gaseous element or compound is favoured. <br/>  <br/> According to this question, decrease in pressure will favour the backward reaction <br/> </div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2019-Model-II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A cell shorthand notation can be written as A/A<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>//B<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>/B. The double lines in the notation represents the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">electrolyte </div>", "<div style=\"font-family:Cambria;font-size:17px;\">solid-liquid interface </div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrodes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">salt bridge </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The double slash in a cell shorthand notation represents a salt bridge. The salt bridge is a device used to connect the oxidation and reduction half-cells of a galvanic cell. It maintains the electrical neutrality within the internal circuit, preventing the cell from rapidly running its reaction to equilibrium.</div>", "topic": "ELECTROLYSIS : ELECTROCHEMICAL CELLS"}, {"id": "objective>Chemistry>2019-Model-II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The shapes of water, ammonia, carbon (iv) oxide and methane are respectively</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tetrahedral, angular, pyramidal and linear </div>", "<div style=\"font-family:Cambria;font-size:17px;\">angular, pyramidal, linear and tetrahedral</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pyramidal, linear, tetrahedral and angular </div>", "<div style=\"font-family:Cambria;font-size:17px;\">linear, tetrahedral, angular and pyramidal</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2019-Model-II/3.png\" style=\"position:relative;max-width:100%;\"/> <br/> (Bent or angular) <br/>  <br/> <img src=\"2019-Model-II/4.png\" style=\"position:relative;max-width:100%;\"/> <br/> (pyramidal) <br/>  <br/> Carbon (iv) oxide <br/>  <br/> O = C = O (linear) <br/>  <br/> <img src=\"2019-Model-II/5.png\" style=\"position:relative;max-width:100%;\"/> <br/> (tetrahedral)</div>", "topic": "ATOMIC STRUCTURE AND BONDING : SHAPES OF SIMPLE MOLECULES"}, {"id": "objective>Chemistry>2019-Model-II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Consider the following reaction equation: <br/> 2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> → 2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> <br/> ∆H = +198 kJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Which of the following statements about the reaction is correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The reaction is exothermic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The reaction container would feel warm.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">198 kJ of energy is given off</div>", "<div style=\"font-family:Cambria;font-size:17px;\">198 kJ of energy is absorbed</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A positive value of ∆H (+198 kJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>) indicates that the reaction is endothermic, meaning it requires an input of energy to proceed. In this case, the reaction absorbs 198 kJ of energy per mole of reactants to convert 2 moles of SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> into 2 moles of SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and 1 mole of O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>. This means that the reaction container would need to be supplied with energy, and it would feel cooler rather than warmer.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2019-Model-II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation state(s) of nitrogen in ammonium nitrite is/are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">-3, +3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-3, +5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-3</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ammonium nitrite = NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> + NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> <br/>  <br/> In NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>, the oxidation state of nitrogen is  <br/> x + 4 = +1 <br/> x = +1 - 4 <br/> x = -3 <br/> In NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>, the oxidation state of nitrogen is  <br/> x - 4 = -1 <br/> x = -1 + 4 <br/> x = +3</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2019-Model-II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen bond is a sort of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a covalent bond </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ionic bond </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dative bond </div>", "<div style=\"font-family:Cambria;font-size:17px;\">van der waals force </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen bond is a covalent intermolecular bond that exists between hydrogen and highly electronegative elements like nitrogen, oxygen and fluorine.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2019-Model-II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Methane is prepared in the laboratory by heating a mixture of  sodium ethanoate with soda lime. The chemical constituent(s) of soda lime is/are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NaOH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">(CaOH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and NaOH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaCl</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Soda lime is a mixture of chemicals, used in granular form in closed breathing environments, such as general anesthesia, submarines, rebreathers and recompression chambers, to remove carbon dioxide from breathing gases to prevent CO2 retention and carbon dioxide poisoning. It is made by treating slaked lime with concentrated sodium hydroxide solution. So, it consists of (CaOH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and NaOH.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2019-Model-II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following sets of operation will completely separate a mixture of sodium chloride, sand and iodine?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">addition of water, filtration, evaporation to dryness and sublimation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sublimation, addition of water, filtration and evaporation to dryness </div>", "<div style=\"font-family:Cambria;font-size:17px;\">filtration, evaporation to dryness, addition of water and sublimation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sublimation, filtration, evaporation and addition of water</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sublimation: <br/>  <br/> Heat the mixture gently. Iodine will sublimate (turn directly from a solid to a gas) and can be collected by cooling the vapor to form solid iodine crystals separately. <br/> Dissolution and Filtration: <br/>  <br/> Dissolve the remaining mixture (salt and sand) in water. Sodium chloride is soluble in water, whereas sand is not. <br/> Filter the solution to separate the sand from the sodium chloride solution. The sand will remain on the filter paper. <br/> Evaporation: <br/>  <br/> Evaporate the water from the sodium chloride solution to obtain solid sodium chloride. <br/> So, the complete set of operations is: sublimation, dissolution in water, filtration, and evaporation.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2019-Model-II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">200cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of 0.50mol/dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> solution of calcium hydrogen trioxocarbonate (IV) is heated. The maximum weight of solid precipitated is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25g</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Equation of reaction <br/> Ca(HCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> (precipitate) + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>  (in the presence of heat) <br/>  <br/> v = 200cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 0.2 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> c = 0.5 mol/dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 0.5M <br/> n = cv ⇒ n = 0.5 × 0.2 = 0.1 mole  <br/> From the equation above <br/> 1 mole of Ca(HCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> gives 100g of CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> (1 mole) <br/> 0.10 mole of Ca(HCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> gives x of CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />0.10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100<hr size=\"1\" />x</td></tr></table></div> <br/> x = 100 × 0.10 = 10.0g</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2019-Model-II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following conditions will most enhance the spontaneity of a reaction?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ΔH is negative and greater than TΔS</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ΔH is negative and ΔS = 0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ΔH is positive and equal to TΔS</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ΔH is positive and less than TΔS</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To determine the sponteinity of reaction, we consider the value of ΔG. <br/> If ΔG is negative, the reaction is spontaneous at that temperature. <br/> If ΔG = +ve, the reaction is not spontaneous at that temperature. <br/> If ΔG = 0, the reaction is at equilibrium <br/>  <br/> Recall: <br/> Δ = δH - TΔS <br/> So, a reaction will be most spontaneous if  <br/> ΔH is negative and greater than TΔS.</div>", "topic": "ENERGY CHANGES : SPONTANEITY OF REACTIONS"}, {"id": "objective>Chemistry>2019-Model-II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">X is a substance which liberates CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> on treatment with concentrated H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>. A warm solution of X can decolorize acidified KMnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> X is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NaHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCOOH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">FeCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It should be noted that for X to liberate CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, X must be a carbonate or an oxalate, since, it decolorizes, KMnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>, X must therefore be an oxalate H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2019-Model-II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The velocity, V of a gas is related to its mass, M by (k = proportionality constant)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">V = k/M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1/2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">V = k/M</div>", "<div style=\"font-family:Cambria;font-size:17px;\">V = (k/M)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1/2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">V = kM<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The velocity of a gas is inversely proportional to the square root of its molar mass. This is known as Graham's law of effusion. Therefore, V = k/M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1/2</span> is the correct relation.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2019-Model-II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The emission of two successive beta particles from the nucleus <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">32</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">15</span>P will produce </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">32</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">16</span>S</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">32</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">17</span>Cl</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">30</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">14</span>Si</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">32</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">13</span>Al</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">32</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">15</span>P → 2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">-1</span>e + <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">a</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">b</span>X <br/> 32 = 2(0) + a <br/> a = 32 <br/> 15 = 2(-1) + b <br/> 15 = -2 + b <br/> b = 17 <br/>  <br/> <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">a</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">b</span>X = <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">32</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">17</span>X</div>", "topic": "NUCLEAR CHEMISTRY : NUCLEAR REACTIONS"}, {"id": "objective>Chemistry>2019-Model-II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen diffused through a porous plug </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">four times as fast as oxygen </div>", "<div style=\"font-family:Cambria;font-size:17px;\">twice as fast as oxygen </div>", "<div style=\"font-family:Cambria;font-size:17px;\">thrice as fast as oxygen </div>", "<div style=\"font-family:Cambria;font-size:17px;\">at the same speed as oxygen </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: From Graham's Law of Diffusion <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">H</span><hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span><hr size=\"1\" />m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">H</span><hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">32<hr size=\"1\" />2</td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">H</span><hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">16&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">H</span><hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4</td></tr></table></div> <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">H</span> = 4 × R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> <br/> Hydrogen diffuses four times as fast as oxygen.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2019-Model-II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the cost of electricity required to discharge 10g of an ion X<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> is ₦20.00, How much would it cost to discharge 6g of ion Y<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>? <br/> [1 faraday = 96,500C, atomic masses are X = 27, Y = 24]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦20.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦10.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦6.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦9.00</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">X<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + 3e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → X <br/> 3F = 2g <br/> xF = 10g <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x<hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<hr size=\"1\" />27</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">10<hr size=\"1\" />9</td><td style=\"text-align:center;\">F</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">10<hr size=\"1\" />9</td><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">is</td><td style=\"text-align:center;\">equivalent</td><td style=\"text-align:center;\">to</td><td style=\"text-align:center;\">₦20.00</td></tr></table></div> <br/> 1F is equivalent to x <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />10<hr size=\"1\" />9</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">x<hr size=\"1\" />20</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">9<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">x<hr size=\"1\" />20</td></tr></table></div> <br/> x = ₦18.00 <br/> 1F is equivalent to ₦18.00 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">will</td><td style=\"text-align:center;\">be</td><td style=\"text-align:center;\">equivalent</td><td style=\"text-align:center;\">to</td><td style=\"text-align:center;\">x</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x<hr size=\"1\" />18</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2<hr size=\"1\" />1</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">18</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">₦9.00</td></tr></table></div></div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2019-Model-II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The cost of discharging 6.0g of a divalent metal, X from its salt is ₦12.00. What is the cost of discharging 9.0g of a trivalent metal, Y from its salt under the same condition? <br/> [X = 63, Y = 27, 1F = 96,500C]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦12.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦27.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦63.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦95.00</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For the divalent metal X <br/> At the cathode, we have  <br/> X<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → X <br/> 2F will discharge 63g of X <br/> xF will discharge 6.0g of X <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6<hr size=\"1\" />63</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12<hr size=\"1\" />63</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4<hr size=\"1\" />21</td><td style=\"text-align:center;\">F</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">4<hr size=\"1\" />21</td><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">₦12.00</td></tr></table></div> <br/> 1F = x <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">4x<hr size=\"1\" />21</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12</td></tr></table></div> <br/> x = ₦63.00 <br/> 1F will cost ₦63.00 <br/>  <br/> For the trivalent metal Y <br/>  <br/> At the cathode, we have <br/> Y<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> + 3e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Y <br/> 3F will discharge 27g of Y <br/> xF will discharge 9.0g of Y <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x<hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">9<hr size=\"1\" />27</td></tr></table></div> <br/> x = 1.0F <br/> It will cost ₦63.00 to discharge such</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2019-Model-II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many alkoxyalkanes can be obtained from the molecular formula C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span>O?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2019-Model-II/6.png\" style=\"position:relative;max-width:100%;\"/> <br/> ethoxylethane <br/>  <br/> <img src=\"2019-Model-II/7.png\" style=\"position:relative;max-width:100%;\"/> <br/> Methoxylpropane <br/>  <br/> <img src=\"2019-Model-II/8.png\" style=\"position:relative;max-width:100%;\"/> <br/> Propoxylmethane</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2019-Model-II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S + SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → 3S + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a redox reaction in which H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S is the oxidant and SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is the reductant </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a redox reaction in which SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is the oxidant and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S is the reductant </div>", "<div style=\"font-family:Cambria;font-size:17px;\">not a redox reaction because there is no oxidant in the reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">not a redox reaction because there is no reductant in the reaction</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S + SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → 3S + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/> In 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S, hydrogen sulphide, the oxidation number of sulphur is -2, it changes to O in 3s, hence H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S has been oxidized ⇒ H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S is the reductant. <br/>  <br/> In SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, sulphur dioxide the oxidation number of sulphur is +4, it changes to O in 3s, hence SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> has been reduced ⇒ SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is the oxidant. <br/>  <br/> N.B: In general H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S is a better reductant than SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2019-Model-II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A solution X, on mixing with AgNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> solution gives a white precipitate soluble in aqueous NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, a solution Y, when also added to X, also gives a white precipitate which is soluble when heated solutions X and Y respectively contain</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ag<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>, SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>, SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pb<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>, Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Al<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span>, Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the information given in the question, solutions X and Y contain lead (II) ion, Pb<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> and sulphate ion respectively.</div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>2019-Model-II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many electrons will be found in the nucleus of an atom with mass number 23 and 17 neutrons?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">6</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">none</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The nucleus of an atom contains protons and neutrons, not electrons. Electrons are found in the electron cloud outside the nucleus. Therefore, the number of electrons in the nucleus of an atom is always zero.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2019-Model-II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An element Z, contains 80% of <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">16</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>Z and 20% of <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">18</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>Z. Its relative atomic mass is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">16.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16.2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16.4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">17.6</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: <br/> R.A.M = m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> + m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>α<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R.A.M</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">16(</td><td style=\"text-align:center;\">80<hr size=\"1\" />100</td><td style=\"text-align:center;\">)+</td><td style=\"text-align:center;\">18(</td><td style=\"text-align:center;\">20<hr size=\"1\" />100</td><td style=\"text-align:center;\">)</td></tr></table></div> <br/> 16(0.8) + 18(0.2) <br/> 12.8 + 3.6 = 16.4</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2019-Model-II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the end alkyl groups of ethyl ethanoate are interchanged, the compound formed is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethylpropanoate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">methyl ethanoate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">propylmethanoate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">methyl propanoate</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The structural formula for methyl ethanoate is  <br/> <img src=\"2019-Model-II/9.png\" style=\"position:relative;max-width:100%;\"/> <br/> When interchanged, we have: <br/> <img src=\"2019-Model-II/10.png\" style=\"position:relative;max-width:100%;\"/> <br/> Methyl propanoate</div>", "topic": "ORGANIC COMPOUNDS : ALKANOATES"}, {"id": "objective>Chemistry>2019-Model-II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following factors will speed up the rate of evolution of carbon (iv) oxide in the reaction below? <br/> 2HCl + CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> → CaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Increasing the surface area of CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reducing the concentration of the acid </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reducing the surface area of CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing both reactant and product</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The rate of a chemical reaction can be increased by increasing the surface area of the reactants. Increasing the surface area of CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> will speed up the rate of evolution of carbon (iv) oxide.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2019-Model-II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The part of the total energy of a system that accounts for the useful work done in a system is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Gibb's free energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Entropy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Enthalpy change </div>", "<div style=\"font-family:Cambria;font-size:17px;\">None of the above</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gibb's free energy is the fraction of the total energy of a system that accounts for how much useful work can be done in a system.</div>", "topic": "ENERGY CHANGES : GIBB'S FREE ENERGY"}];
